package main
import (
    "fmt"
    "strconv"
)

func main() {
    // Atoy works, but what about Aboi?
    number, err := strconv.Atoi("100 abc")

    // Always check err!
    if err != nil {
        fmt.Println("Uh oh! Error:", err)
        return // Stop the function
    }

    fmt.Println("Success! Number is", number)
}
